414+00', 2, 2, 0, true, '[{"bot": "Estos son los servicios disponibles en Ahumada Detailing:\\n\\n1. Lavado básico\\nIdeal para mantener tu vehículo limpio y cuidado en el día a día. Incluye una limpieza interior y exterior general.\\n\\n2. Lavado premium\\nNuestra opción más completa. Recomendado si buscas una limpieza más detallada por dentro y por fuera, con una terminación más cuidada.\\n\\n3. Encerado full\\nServicio enfocado en proteger la pintura y realzar el brillo del vehículo. Ideal para darle una mejor terminación y mayor protección exterior.\\n\\nPara darte el valor exacto, dime qué tipo de vehículo tienes y en qué comuna sería el servicio.", "audit": {"meta": {"bot": "Estos son los servicios disponibles en Ahumada Detailing:\\n\\n1. Lavado básico\\nIdeal para mantener tu vehículo limpio y cuidado en el día a día. Incluye una limpieza interior y exterior general.\\n\\n2. Lavado premium\\nNuestra opción más completa. Recomendado si buscas una limpieza más detallada por dentro y por fuera, con una terminación más cuidada.\\n\\n3. Encerado full\\nServicio enfocado en proteger la pintura y realzar el brillo del vehículo. Ideal para darle una mejor terminación y mayor protección exterior.\\n\\nPara darte el valor exacto, dime qué tipo de vehículo tienes y en qué comuna sería el servicio.", "notes": [], "state": {"before": {"stage": "service_discovery", "address": null, "lead_id": "0ecab7da-9e3a-4b46-9add-91ad52d1763f", "slot_id": null, "district": null, "max_slots": 0, "next_goal": "collect_vehicle_and_district", "days_ahead": 0, "calendar_id": null, "intent_last": "service_menu_request", "booking_date": null, "booking_time": null, "vehicle_type": null, "followup_type": null, "human_handoff": false, "scheduled_for": null, "service_scope": null, "interest_score": 0, "missing_fields": [], "booking_options": [], "last_bot_action": "send_service_menu", "service_address": null, "duration_minutes": 120, "service_interest": null, "address_confirmed": false, "address